static OpenMPDirectiveKind mapDirectiveNameToKind(const char* name) {
    // Map ROUP directive name strings to ompparser directive kinds
    // This is the authoritative mapping since integer kinds are ambiguous
    if (!name) return OMPD_unknown;

    std::string n(name);

    // Single-word directives
    if (n == "parallel") return OMPD_parallel;
    if (n == "for") return OMPD_for;
    if (n == "do") return OMPD_do;
    if (n == "sections") return OMPD_sections;
    if (n == "section") return OMPD_section;
    if (n == "single") return OMPD_single;
    if (n == "task") return OMPD_task;
    if (n == "master") return OMPD_master;
    if (n == "critical") return OMPD_critical;
    if (n == "barrier") return OMPD_barrier;
    if (n == "taskwait") return OMPD_taskwait;
    if (n == "taskgroup") return OMPD_taskgroup;
    if (n == "atomic") return OMPD_atomic;
    if (n == "flush") return OMPD_flush;
    if (n == "ordered") return OMPD_ordered;
    if (n == "target") return OMPD_target;
    if (n == "teams") return OMPD_teams;
    if (n == "distribute") return OMPD_distribute;
    if (n == "simd") return OMPD_simd;
    if (n == "loop") return OMPD_loop;
    if (n == "scan") return OMPD_scan;
    if (n == "workshare") return OMPD_workshare;
    if (n == "masked") return OMPD_masked;
    if (n == "scope") return OMPD_scope;
    if (n == "metadirective") return OMPD_metadirective;
    if (n == "cancel") return OMPD_cancel;
    if (n == "end") return OMPD_end;

    // END directives (Fortran) - all map to OMPD_end, parameter has the directive being ended
    if (n == "end parallel") return OMPD_end;
    if (n == "end for") return OMPD_end;
    if (n == "end do") return OMPD_end;
    if (n == "end sections") return OMPD_end;
    if (n == "end single") return OMPD_end;
    if (n == "end task") return OMPD_end;
    if (n == "end master") return OMPD_end;
    if (n == "end critical") return OMPD_end;
    if (n == "end taskgroup") return OMPD_end;
    if (n == "end target") return OMPD_end;
    if (n == "end teams") return OMPD_end;
    if (n == "end distribute") return OMPD_end;
    if (n == "end simd") return OMPD_end;
    if (n == "end loop") return OMPD_end;
    if (n == "end workshare") return OMPD_end;
    if (n == "end masked") return OMPD_end;
    if (n == "end scope") return OMPD_end;
    if (n == "end parallel for") return OMPD_end;
    if (n == "end parallel do") return OMPD_end;
    if (n == "end parallel sections") return OMPD_end;
    if (n == "end parallel single") return OMPD_end;
    if (n == "end parallel workshare") return OMPD_end;
    if (n == "end parallel master") return OMPD_end;
    if (n == "end parallel loop") return OMPD_end;
    if (n == "end for simd") return OMPD_end;
    if (n == "end do simd") return OMPD_end;
    if (n == "end target parallel") return OMPD_end;
    if (n == "end target teams") return OMPD_end;
    if (n == "end target data") return OMPD_end;
    if (n == "end target simd") return OMPD_end;
    if (n == "end teams distribute") return OMPD_end;
    if (n == "end distribute simd") return OMPD_end;
    if (n == "end taskloop simd") return OMPD_end;
    if (n == "end master taskloop") return OMPD_end;
    if (n == "end masked taskloop") return OMPD_end;
    if (n == "end teams loop") return OMPD_end;
    if (n == "end parallel for simd") return OMPD_end;
    if (n == "end parallel do simd") return OMPD_end;
    if (n == "end target parallel for") return OMPD_end;
    if (n == "end target parallel do") return OMPD_end;
    if (n == "end target parallel loop") return OMPD_end;
    if (n == "end target teams distribute") return OMPD_end;
    if (n == "end target teams loop") return OMPD_end;
    if (n == "end teams distribute simd") return OMPD_end;
    if (n == "end distribute parallel for") return OMPD_end;
    if (n == "end distribute parallel do") return OMPD_end;
    if (n == "end master taskloop simd") return OMPD_end;
    if (n == "end masked taskloop simd") return OMPD_end;
    if (n == "end parallel master taskloop") return OMPD_end;
    if (n == "end target parallel for simd") return OMPD_end;
    if (n == "end target parallel do simd") return OMPD_end;
    if (n == "end target teams distribute simd") return OMPD_end;
    if (n == "end distribute parallel for simd") return OMPD_end;
    if (n == "end distribute parallel do simd") return OMPD_end;
    if (n == "end target teams distribute parallel") return OMPD_end;
    if (n == "end parallel master taskloop simd") return OMPD_end;
    if (n == "end target teams distribute parallel for") return OMPD_end;
    if (n == "end target teams distribute parallel do") return OMPD_end;
    if (n == "end target teams distribute parallel for simd") return OMPD_end;
    if (n == "end target teams distribute parallel do simd") return OMPD_end;

    // Two-word directives
    if (n == "parallel for") return OMPD_parallel_for;
    if (n == "parallel do") return OMPD_parallel_do;
    if (n == "parallel sections") return OMPD_parallel_sections;
    if (n == "parallel single") return OMPD_parallel_single;
    if (n == "parallel workshare") return OMPD_parallel_workshare;
    if (n == "parallel master") return OMPD_parallel_master;
    if (n == "parallel loop") return OMPD_parallel_loop;
    if (n == "for simd") return OMPD_for_simd;
    if (n == "do simd") return OMPD_do_simd;
    if (n == "target parallel") return OMPD_target_parallel;
    if (n == "target teams") return OMPD_target_teams;
    if (n == "target data") return OMPD_target_data;
    if (n == "target simd") return OMPD_target_simd;
    if (n == "teams distribute") return OMPD_teams_distribute;
    if (n == "distribute simd") return OMPD_distribute_simd;
    if (n == "distribute parallel") return OMPD_distribute_parallel_for;
    if (n == "taskloop simd") return OMPD_taskloop_simd;
    if (n == "master taskloop") return OMPD_master_taskloop;
    if (n == "masked taskloop") return OMPD_masked_taskloop;
    if (n == "teams loop") return OMPD_teams_loop;

    // Three-word directives
    if (n == "parallel for simd") return OMPD_parallel_for_simd;
    if (n == "parallel do simd") return OMPD_parallel_do_simd;
    if (n == "target parallel for") return OMPD_target_parallel_for;
    if (n == "target parallel do") return OMPD_target_parallel_do;
    if (n == "target parallel loop") return OMPD_target_parallel_loop;
    if (n == "target teams distribute") return OMPD_target_teams_distribute;
    if (n == "target teams loop") return OMPD_target_teams_loop;
    if (n == "teams distribute simd") return OMPD_teams_distribute_simd;
    if (n == "distribute parallel for") return OMPD_distribute_parallel_for;
    if (n == "distribute parallel do") return OMPD_distribute_parallel_do;
    if (n == "master taskloop simd") return OMPD_master_taskloop_simd;
    if (n == "masked taskloop simd") return OMPD_masked_taskloop_simd;
    if (n == "parallel master taskloop") return OMPD_parallel_master_taskloop;

    // Four-word directives
    if (n == "target parallel for simd") return OMPD_target_parallel_for_simd;
    if (n == "target parallel do simd") return OMPD_target_parallel_do_simd;
    if (n == "target teams distribute simd") return OMPD_target_teams_distribute_simd;
    if (n == "distribute parallel for simd") return OMPD_distribute_parallel_for_simd;
    if (n == "distribute parallel do simd") return OMPD_distribute_parallel_do_simd;
    if (n == "target teams distribute parallel") return OMPD_target_teams_distribute_parallel_for;
    if (n == "parallel master taskloop simd") return OMPD_parallel_master_taskloop_simd;

    // Five-word directives
    if (n == "target teams distribute parallel for") return OMPD_target_teams_distribute_parallel_for;
    if (n == "target teams distribute parallel do") return OMPD_target_teams_distribute_parallel_do;

    // Six-word directives
    if (n == "target teams distribute parallel for simd") return OMPD_target_teams_distribute_parallel_for_simd;
    if (n == "target teams distribute parallel do simd") return OMPD_target_teams_distribute_parallel_do_simd;

    // declare/special directives
    if (n == "allocate") return OMPD_allocate;
    if (n == "threadprivate") return OMPD_threadprivate;
    if (n == "groupprivate") return OMPD_groupprivate;
    if (n == "declare simd") return OMPD_declare_simd;
    if (n == "declare reduction") return OMPD_declare_reduction;
    if (n == "declare mapper") return OMPD_declare_mapper;
    if (n == "declare target") return OMPD_declare_target;
    if (n == "declare variant") return OMPD_declare_variant;
    if (n == "begin declare target") return OMPD_begin_declare_target;
    if (n == "end declare target") return OMPD_end_declare_target;
    if (n == "begin declare variant") return OMPD_begin_declare_variant;
    if (n == "end declare variant") return OMPD_end_declare_variant;
    if (n == "taskyield") return OMPD_taskyield;
    if (n == "taskloop") return OMPD_taskloop;
    if (n == "target enter data") return OMPD_target_enter_data;
    if (n == "target exit data") return OMPD_target_exit_data;
    if (n == "target update") return OMPD_target_update;
    if (n == "requires") return OMPD_requires;
    if (n == "depobj") return OMPD_depobj;
    if (n == "cancellation point") return OMPD_cancellation_point;

    // atomic variants
    if (n == "atomic read") return OMPD_atomic;
    if (n == "atomic write") return OMPD_atomic;
    if (n == "atomic update") return OMPD_atomic;
    if (n == "atomic capture") return OMPD_atomic;

    return OMPD_unknown;
}

static OpenMPDirectiveKind mapRoupToOmpparserDirective(int32_t roup_kind) {
    // Map ROUP DirectiveKind enum (src/ir/directive.rs) to ompparser OpenMPDirectiveKind
    // Each directive has a unique enum value - NO MORE COLLAPSING!
    switch (roup_kind) {
        // Special case: -1 means parse_directive_kind couldn't map the name to an enum
        // This happens for generic "end" directives in Fortran
        case -1:  return OMPD_end;

        // Parallel constructs
        case 0:   return OMPD_parallel;
        case 1:   return OMPD_parallel_for;
        case 2:   return OMPD_parallel_for_simd;
        case 3:   return OMPD_parallel_sections;
        case 4:   return OMPD_parallel_workshare;
        case 5:   return OMPD_parallel_loop;
        case 6:   return OMPD_parallel_masked;
        case 7:   return OMPD_parallel_master;
        case 8:   return OMPD_parallel_loop;  // parallel_loop_simd
        case 9:   return OMPD_parallel_masked_taskloop;
        case 17:  return OMPD_parallel_masked_taskloop_simd;
        case 18:  return OMPD_parallel_master_taskloop;
        case 19:  return OMPD_parallel_master_taskloop_simd;

        // Work-sharing constructs
        case 10:  return OMPD_for;
        case 11:  return OMPD_for_simd;
        case 12:  return OMPD_sections;
        case 13:  return OMPD_section;
        case 14:  return OMPD_single;
        case 15:  return OMPD_workshare;
        case 16:  return OMPD_loop;

        // SIMD constructs
        case 20:  return OMPD_simd;
        case 21:  return OMPD_declare_simd;

        // Task constructs
        case 30:  return OMPD_task;
        case 31:  return OMPD_taskloop;
        case 32:  return OMPD_taskloop_simd;
        case 33:  return OMPD_taskyield;
        case 34:  return OMPD_taskwait;
        case 35:  return OMPD_taskgroup;
        case 38:  return OMPD_masked_taskloop;
        case 39:  return OMPD_masked_taskloop_simd;

        // Target constructs
        case 40:  return OMPD_target;
        case 41:  return OMPD_target_data;
        case 42:  return OMPD_target_enter_data;
        case 43:  return OMPD_target_exit_data;
        case 44:  return OMPD_target_update;
        case 45:  return OMPD_target_parallel;
        case 46:  return OMPD_target_parallel_for;
        case 47:  return OMPD_target_parallel_for_simd;
        case 48:  return OMPD_target_parallel_loop;
        case 49:  return OMPD_target_simd;
        case 50:  return OMPD_target_teams;
        case 51:  return OMPD_target_teams_distribute;
        case 52:  return OMPD_target_teams_distribute_simd;
        case 53:  return OMPD_target_teams_distribute_parallel_for;
        case 54:  return OMPD_target_teams_distribute_parallel_for_simd;
        case 55:  return OMPD_target_teams_loop;
        case 56:  return OMPD_target_parallel_loop;  // target_parallel_loop_simd
        case 57:  return OMPD_target;  // target_loop
        case 58:  return OMPD_target;  // target_loop_simd

        // Teams constructs
        case 60:  return OMPD_teams;
        case 61:  return OMPD_teams_distribute;
        case 62:  return OMPD_teams_distribute_simd;
        case 63:  return OMPD_teams_distribute_parallel_for;
        case 64:  return OMPD_teams_distribute_parallel_for_simd;
        case 65:  return OMPD_teams_loop;
        case 66:  return OMPD_teams_distribute_parallel_for;  // teams_distribute_parallel_loop
        case 67:  return OMPD_teams_distribute_parallel_for_simd;  // teams_distribute_parallel_loop_simd
        case 68:  return OMPD_teams_loop;  // teams_loop_simd

        // Synchronization constructs
        case 70:  return OMPD_barrier;
        case 71:  return OMPD_critical;
        case 72:  return OMPD_atomic;
        case 73:  return OMPD_flush;
        case 74:  return OMPD_ordered;
        case 75:  return OMPD_master;
        case 76:  return OMPD_masked;
        case 77:  return OMPD_atomic;  // atomic_read
        case 78:  return OMPD_atomic;  // atomic_write
        case 79:  return OMPD_atomic;  // atomic_update
        case 86:  return OMPD_atomic;  // atomic_capture
        case 87:  return OMPD_atomic;  // atomic_compare_capture

        // Declare constructs
        case 80:  return OMPD_declare_reduction;
        case 81:  return OMPD_declare_mapper;
        case 82:  return OMPD_declare_target;
        case 83:  return OMPD_declare_variant;

        // Distribute constructs
        case 90:  return OMPD_distribute;
        case 91:  return OMPD_distribute_simd;
        case 92:  return OMPD_distribute_parallel_for;
        case 93:  return OMPD_distribute_parallel_for_simd;
        case 94:  return OMPD_distribute_parallel_for;  // distribute_parallel_loop
        case 95:  return OMPD_distribute_parallel_for_simd;  // distribute_parallel_loop_simd

        // Meta-directives
        case 100: return OMPD_metadirective;

        // Other constructs
        case 120: return OMPD_threadprivate;
        case 121: return OMPD_allocate;
        case 123: return OMPD_requires;
        case 124: return OMPD_scan;
        case 125: return OMPD_depobj;
        case 128: return OMPD_cancel;
        case 129: return OMPD_cancellation_point;

        // Fortran "do" variants
        case 135: return OMPD_do;
        case 136: return OMPD_do_simd;
        case 137: return OMPD_parallel_do;
        case 138: return OMPD_parallel_do_simd;
        case 139: return OMPD_distribute_parallel_do;
        case 140: return OMPD_distribute_parallel_do_simd;
        case 141: return OMPD_teams_distribute_parallel_do;
        case 142: return OMPD_teams_distribute_parallel_do_simd;
        case 143: return OMPD_target_parallel_do;
        case 144: return OMPD_target_parallel_do_simd;
        case 145: return OMPD_target_teams_distribute_parallel_do;
        case 146: return OMPD_target_teams_distribute_parallel_do_simd;

        // END directive
        case 147: return OMPD_end;  // end_target or generic end

        default:  return OMPD_unknown;
    }
}

static OpenMPClauseKind mapRoupToOmpparserClause(int32_t roup_kind) {
    // ROUP clause kind mapping using named constants from roup_constants.h
    // Single source of truth: src/c_api.rs:convert_clause()
    switch (roup_kind) {
        case ROUP_CLAUSE_NUM_THREADS:   return OMPC_num_threads;
        case ROUP_CLAUSE_IF:            return OMPC_if;
        case ROUP_CLAUSE_PRIVATE:       return OMPC_private;
        case ROUP_CLAUSE_SHARED:        return OMPC_shared;
        case ROUP_CLAUSE_FIRSTPRIVATE:  return OMPC_firstprivate;
        case ROUP_CLAUSE_LASTPRIVATE:   return OMPC_lastprivate;
        case ROUP_CLAUSE_REDUCTION:     return OMPC_reduction;
        case ROUP_CLAUSE_SCHEDULE:      return OMPC_schedule;
        case ROUP_CLAUSE_COLLAPSE:      return OMPC_collapse;
        case ROUP_CLAUSE_ORDERED:       return OMPC_ordered;
        case ROUP_CLAUSE_NOWAIT:        return OMPC_nowait;
        case ROUP_CLAUSE_DEFAULT:       return OMPC_default;
        // Memory order clauses (values from c_api.rs)
        case 12:                        return OMPC_seq_cst;
        case 13:                        return OMPC_release;
        case 14:                        return OMPC_acquire;
        case 15:                        return OMPC_acq_rel;
        case 16:                        return OMPC_relaxed;
        // Atomic operation clauses
        case 17:                        return OMPC_read;
        case 18:                        return OMPC_write;
        case 19:                        return OMPC_update;
        case 20:                        return OMPC_capture;
        case 21:                        return OMPC_compare;
        // Other common clauses
        case 22:                        return OMPC_hint;
        case 23:                        return OMPC_allocate;
        case 24:                        return OMPC_allocator;
        case 25:                        return OMPC_align;
        case 26:                        return OMPC_proc_bind;
        default:                        return OMPC_unknown;
    }
}

// ============================================================================
// Main Entry Point
// ============================================================================

extern "C" {

OpenMPDirective* parseOpenMP(const char* input, void* exprParse(const char* expr)) {
    if (!input || input[0] == '\0') {
        return nullptr;
    }

    // Validate input length using constant from ROUP C API
    // Use strnlen to safely handle potentially untrusted/non-null-terminated input
    const size_t input_len = strnlen(input, ROUP_MAX_PRAGMA_LENGTH);
    if (input_len == ROUP_MAX_PRAGMA_LENGTH) {
        return nullptr;  // Input too long or not null-terminated within limit
    }

    // Determine input format based on current language mode
    std::string input_str(input, input_len);

    // Handle different language pragmas
    if (current_lang == Lang_Fortran) {
        // Fortran uses !$omp prefix - add if missing (case-insensitive check)
        const bool has_prefix =
            input_str.length() >= FORTRAN_PREFIX_LEN &&
            (input_str.compare(0, FORTRAN_PREFIX_LEN, FORTRAN_PREFIX) == 0 ||
             input_str.compare(0, FORTRAN_PREFIX_LEN, FORTRAN_PREFIX_UPPER) == 0);
        if (!has_prefix) {
            input_str = std::string(FORTRAN_PREFIX) + " " + input_str;
        }
    } else {
        // C/C++ use #pragma omp prefix - add if missing
        // compare() returns 0 if strings match, non-zero otherwise
        if (input_str.compare(0, C_PRAGMA_PREFIX_LEN, C_PRAGMA_PREFIX) != 0) {
            input_str = std::string(C_PRAGMA_PREFIX) + " " + input_str;
        }
    }

    // Call ROUP parser with language-aware parsing
    // Use ROUP language constants: ROUP_LANG_C (0), ROUP_LANG_FORTRAN_FREE (1)
    int32_t roup_lang = (current_lang == Lang_Fortran) ? ROUP_LANG_FORTRAN_FREE : 0;
    OmpDirective* roup_dir = roup_parse_with_language(input_str.c_str(), roup_lang);
    if (!roup_dir) {
        return nullptr;
    }

    // Get directive kind from ROUP (DirectiveKind enum value)
    int32_t roup_kind = roup_directive_kind(roup_dir);

    // Get directive name (needed for END directive handling)
    const char* directive_name = roup_directive_name(roup_dir);

    // Map ROUP DirectiveKind enum to ompparser OpenMPDirectiveKind enum
    OpenMPDirectiveKind kind = mapRoupToOmpparserDirective(roup_kind);

    // Create ompparser-compatible directive - use specialized types where needed
    OpenMPDirective* dir = nullptr;

    // Create specialized directive types for directives that need them
    switch (kind) {
        case OMPD_atomic:
            dir = new OpenMPAtomicDirective();
            break;
        case OMPD_critical:
            dir = new OpenMPCriticalDirective();
            break;
        case OMPD_flush:
            dir = new OpenMPFlushDirective();
            break;
        case OMPD_ordered:
            dir = new OpenMPOrderedDirective();
            break;
        case OMPD_depobj:
            dir = new OpenMPDepobjDirective();
            break;
        case OMPD_allocate:
            dir = new OpenMPAllocateDirective();
            break;
        case OMPD_threadprivate:
            dir = new OpenMPThreadprivateDirective();
            break;
        case OMPD_groupprivate:
            dir = new OpenMPGroupprivateDirective();
            break;
        case OMPD_declare_simd:
            dir = new OpenMPDeclareSimdDirective();
            break;
        case OMPD_declare_reduction:
            dir = new OpenMPDeclareReductionDirective();
            break;
        case OMPD_declare_variant:
            dir = new OpenMPDeclareVariantDirective();
            break;
        case OMPD_requires:
            dir = new OpenMPRequiresDirective();
            break;
        case OMPD_end:
            dir = new OpenMPEndDirective();
            break;
        default:
            // Use generic OpenMPDirective for other directive types
            dir = new OpenMPDirective(kind, current_lang, 0, 0);
            break;
    }

    // Set base language for all directive types (generic constructor sets it, but specialized types need it)
    if (dir) {
        dir->setBaseLang(current_lang);
    }

    // Get directive parameter (for allocate variable lists, cancel construct types, etc.)
    char* param_str = roup_directive_parameter(roup_dir);
    if (param_str) {
        std::string param(param_str);
        roup_string_free(param_str);

        // Handle allocate directive - parse (a,b,c) into individual variables
        if (kind == OMPD_allocate) {
            // Remove parentheses and split by comma
            if (param.size() >= 2 && param.front() == '(' && param.back() == ')') {
                std::string list_content = param.substr(1, param.size() - 2);
                std::istringstream ss(list_content);
                std::string var;
                while (std::getline(ss, var, ',')) {
                    // Trim whitespace
                    var.erase(0, var.find_first_not_of(" \t"));
                    var.erase(var.find_last_not_of(" \t") + 1);
                    if (!var.empty()) {
                        static_cast<OpenMPAllocateDirective*>(dir)->addAllocateList(strdup(var.c_str()));
                    }
                }
            }
        }
        // Handle threadprivate directive
        else if (kind == OMPD_threadprivate) {
            if (param.size() >= 2 && param.front() == '(' && param.back() == ')') {
                std::string list_content = param.substr(1, param.size() - 2);
                std::istringstream ss(list_content);
                std::string var;
                while (std::getline(ss, var, ',')) {
                    var.erase(0, var.find_first_not_of(" \t"));
                    var.erase(var.find_last_not_of(" \t") + 1);
                    if (!var.empty()) {
                        static_cast<OpenMPThreadprivateDirective*>(dir)->addThreadprivateList(strdup(var.c_str()));
                    }
                }
            }
        }
        // Handle groupprivate directive
        else if (kind == OMPD_groupprivate) {
            if (param.size() >= 2 && param.front() == '(' && param.back() == ')') {
                std::string list_content = param.substr(1, param.size() - 2);
                std::istringstream ss(list_content);
                std::string var;
                while (std::getline(ss, var, ',')) {
                    var.erase(0, var.find_first_not_of(" \t"));
                    var.erase(var.find_last_not_of(" \t") + 1);
                    if (!var.empty()) {
                        static_cast<OpenMPGroupprivateDirective*>(dir)->addGroupprivateList(strdup(var.c_str()));
                    }
                }
            }
        }
        // Handle critical directive - extract name
        else if (kind == OMPD_critical) {
            if (param.size() >= 2 && param.front() == '(' && param.back() == ')') {
                std::string name = param.substr(1, param.size() - 2);
                // Trim whitespace
                name.erase(0, name.find_first_not_of(" \t"));
                name.erase(name.find_last_not_of(" \t") + 1);
                if (!name.empty()) {
                    static_cast<OpenMPCriticalDirective*>(dir)->setCriticalName(name.c_str());
                }
            }
        }
        // Handle END directive - create paired directive from directive name
        else if (kind == OMPD_end) {
            // For END directives, extract the directive being ended from the name
            // e.g., "end atomic" → "atomic", "end parallel" → "parallel"
            std::string ended_directive;
            std::string dir_name(directive_name);
            if (dir_name.compare(0, 4, "end ") == 0 && dir_name.length() > 4) {
                ended_directive = dir_name.substr(4); // Skip "end "
            } else if (!param.empty()) {
                ended_directive = param; // Fallback to parameter
            }

            // Create a dummy directive to avoid segfault in generatePragmaString
            OpenMPDirectiveKind paired_kind = OMPD_unknown;

            // Map directive names to their kinds
            if (ended_directive == "parallel") paired_kind = OMPD_parallel;
            else if (ended_directive == "do" || ended_directive == "for") paired_kind = OMPD_for;
            else if (ended_directive == "task") paired_kind = OMPD_task;
            else if (ended_directive == "sections") paired_kind = OMPD_sections;
            else if (ended_directive == "single") paired_kind = OMPD_single;
            else if (ended_directive == "workshare") paired_kind = OMPD_workshare;
            else if (ended_directive == "atomic") paired_kind = OMPD_atomic;
            else if (ended_directive == "parallel do" || ended_directive == "parallel for") paired_kind = OMPD_parallel_for;
            else if (ended_directive == "target") paired_kind = OMPD_target;
            else if (ended_directive == "target parallel") paired_kind = OMPD_target_parallel;
            else if (ended_directive == "teams") paired_kind = OMPD_teams;
            else if (ended_directive == "distribute") paired_kind = OMPD_distribute;
            else if (ended_directive == "taskgroup") paired_kind = OMPD_taskgroup;
            else if (ended_directive == "loop") paired_kind = OMPD_loop;
            else if (ended_directive == "master") paired_kind = OMPD_master;
            else if (ended_directive == "masked") paired_kind = OMPD_masked;
            else if (ended_directive == "critical") paired_kind = OMPD_critical;
            else if (ended_directive == "ordered") paired_kind = OMPD_ordered;
            else if (ended_directive == "simd") paired_kind = OMPD_simd;
            // Use mapDirectiveNameToKind for any unhandled directives
            else {
                paired_kind = mapDirectiveNameToKind(ended_directive.c_str());
            }

            // Create dummy paired directive
            OpenMPDirective* paired = new OpenMPDirective(paired_kind, current_lang, 0, 0);
            static_cast<OpenMPEndDirective*>(dir)->setPairedDirective(paired);
        }
        // Handle cancel/cancellation_point - add construct type as a clause
        else if (kind == OMPD_cancel || kind == OMPD_cancellation_point) {
            // The parameter is the construct type (parallel, sections, for, taskgroup)
            // Add it as the appropriate clause
            if (!param.empty()) {
                if (param == "parallel") {
                    dir->addOpenMPClause(OMPC_parallel);
                } else if (param == "sections") {
                    dir->addOpenMPClause(OMPC_sections);
                } else if (param == "for") {
                    dir->addOpenMPClause(OMPC_for);
                } else if (param == "do") {
                    dir->addOpenMPClause(OMPC_do);
                } else if (param == "taskgroup") {
                    dir->addOpenMPClause(OMPC_taskgroup);
                }
            }
        }
    }

    // Handle atomic variants - ROUP parses "atomic read" as directive AtomicRead,
    // but ompparser expects directive atomic + clause read
    // DirectiveKind enum values: AtomicRead=77, AtomicWrite=78, AtomicUpdate=79, AtomicCapture=86, AtomicCompareCapture=87
    if (roup_kind == 77) { // AtomicRead
        dir->addOpenMPClause(OMPC_read);
    } else if (roup_kind == 78) { // AtomicWrite
        dir->addOpenMPClause(OMPC_write);
    } else if (roup_kind == 79) { // AtomicUpdate
        dir->addOpenMPClause(OMPC_update);
    } else if (roup_kind == 86) { // AtomicCapture
        dir->addOpenMPClause(OMPC_capture);
    } else if (roup_kind == 87) { // AtomicCompareCapture
        dir->addOpenMPClause(OMPC_compare);
        dir->addOpenMPClause(OMPC_capture);
    }

    // Convert clauses using ompparser's addOpenMPClause method
    OmpClauseIterator* iter = roup_directive_clauses_iter(roup_dir);
    if (iter) {
        const OmpClause* roup_clause;
        while (roup_clause_iterator_next(iter, &roup_clause) == 1) {
            int32_t roup_kind_clause = roup_clause_kind(roup_clause);
            OpenMPClauseKind clause_kind = mapRoupToOmpparserClause(roup_kind_clause);

            OpenMPClause* new_clause = nullptr;

            // Handle reduction clauses - need operator parameter
            if (clause_kind == OMPC_reduction || clause_kind == OMPC_in_reduction || clause_kind == OMPC_task_reduction) {
                int32_t roup_op = roup_clause_reduction_operator(roup_clause);
                OpenMPReductionClauseIdentifier omp_op;

                // Map ROUP ReductionOperator enum to ompparser OpenMPReductionClauseIdentifier
                switch (roup_op) {
                    case 0:  omp_op = OMPC_REDUCTION_IDENTIFIER_plus; break;     // Add
                    case 1:  omp_op = OMPC_REDUCTION_IDENTIFIER_mul; break;      // Multiply
                    case 2:  omp_op = OMPC_REDUCTION_IDENTIFIER_minus; break;    // Subtract
                    case 10: omp_op = OMPC_REDUCTION_IDENTIFIER_bitand; break;   // BitwiseAnd
                    case 11: omp_op = OMPC_REDUCTION_IDENTIFIER_bitor; break;    // BitwiseOr
                    case 12: omp_op = OMPC_REDUCTION_IDENTIFIER_bitxor; break;   // BitwiseXor
                    case 20: omp_op = OMPC_REDUCTION_IDENTIFIER_logand; break;   // LogicalAnd
                    case 21: omp_op = OMPC_REDUCTION_IDENTIFIER_logor; break;    // LogicalOr
                    case 30: omp_op = OMPC_REDUCTION_IDENTIFIER_min; break;      // Min
                    case 31: omp_op = OMPC_REDUCTION_IDENTIFIER_max; break;      // Max
                    default: omp_op = OMPC_REDUCTION_IDENTIFIER_user; break;     // Unknown/custom
                }

                // Reduction clause va_args: modifier, identifier, user_defined_modifier, user_defined_identifier
                new_clause = dir->addOpenMPClause(static_cast<int>(clause_kind),
                                                 OMPC_REDUCTION_MODIFIER_unspecified,
                                                 omp_op,
                                                 (char*)nullptr,
                                                 (char*)nullptr);
            }
            // Handle schedule clause - needs modifiers and schedule kind
            else if (clause_kind == OMPC_schedule) {
                int32_t roup_sched = roup_clause_schedule_kind(roup_clause);
                OpenMPScheduleClauseKind omp_sched;

                // Map ROUP ScheduleKind enum to ompparser OpenMPScheduleClauseKind
                switch (roup_sched) {
                    case 0: omp_sched = OMPC_SCHEDULE_KIND_static; break;
                    case 1: omp_sched = OMPC_SCHEDULE_KIND_dynamic; break;
                    case 2: omp_sched = OMPC_SCHEDULE_KIND_guided; break;
                    case 3: omp_sched = OMPC_SCHEDULE_KIND_auto; break;
                    case 4: omp_sched = OMPC_SCHEDULE_KIND_runtime; break;
                    default: omp_sched = OMPC_SCHEDULE_KIND_unspecified; break;
                }

                // For now, use unspecified modifiers (monotonic/nonmonotonic/simd)
                // ROUP would need to expose these if they're parsed
                new_clause = dir->addOpenMPClause(static_cast<int>(clause_kind),
                                                 OMPC_SCHEDULE_MODIFIER_unspecified,
                                                 OMPC_SCHEDULE_MODIFIER_unspecified,
                                                 omp_sched);
            }
            // Handle if clause - needs modifier extraction from "if(modifier: expr)" or "if(expr)"
            else if (clause_kind == OMPC_if) {
                OmpStringList* vars = roup_clause_variables(roup_clause);
                OpenMPIfClauseModifier modifier = OMPC_IF_MODIFIER_unspecified;
                char* user_modifier = nullptr;

                if (vars && roup_string_list_len(vars) > 0) {
                    const char* content = roup_string_list_get(vars, 0);
                    if (content) {
                        std::string if_content(content);
                        // Check for modifier format "modifier: expr"
                        size_t colon_pos = if_content.find(':');
                        if (colon_pos != std::string::npos) {
                            std::string mod_str = if_content.substr(0, colon_pos);
                            // Trim whitespace
                            mod_str.erase(0, mod_str.find_first_not_of(" \t"));
                            mod_str.erase(mod_str.find_last_not_of(" \t") + 1);

                            // Map modifier string to enum
                            if (mod_str == "parallel") modifier = OMPC_IF_MODIFIER_parallel;
                            else if (mod_str == "simd") modifier = OMPC_IF_MODIFIER_simd;
                            else if (mod_str == "task") modifier = OMPC_IF_MODIFIER_task;
                            else if (mod_str == "cancel") modifier = OMPC_IF_MODIFIER_cancel;
                            else if (mod_str == "target") modifier = OMPC_IF_MODIFIER_target;
                            else if (mod_str == "target data") modifier = OMPC_IF_MODIFIER_target_data;
                            else if (mod_str == "target enter data") modifier = OMPC_IF_MODIFIER_target_enter_data;
                            else if (mod_str == "target exit data") modifier = OMPC_IF_MODIFIER_target_exit_data;
                            else if (mod_str == "target update") modifier = OMPC_IF_MODIFIER_target_update;
                            else if (mod_str == "taskloop") modifier = OMPC_IF_MODIFIER_taskloop;
                            else {
                                modifier = OMPC_IF_MODIFIER_user;
                                user_modifier = strdup(mod_str.c_str());
                            }

                            // Extract expression after colon
                            std::string expr = if_content.substr(colon_pos + 1);
                            expr.erase(0, expr.find_first_not_of(" \t"));
                            expr.erase(expr.find_last_not_of(" \t") + 1);

                            new_clause = dir->addOpenMPClause(static_cast<int>(clause_kind), modifier, user_modifier);
                            if (new_clause && !expr.empty()) {
                                new_clause->addLangExpr(strdup(expr.c_str()));
                            }
                        } else {
                            // No modifier, just expression
                            new_clause = dir->addOpenMPClause(static_cast<int>(clause_kind), OMPC_IF_MODIFIER_unspecified, (char*)nullptr);
                            if (new_clause) {
                                new_clause->addLangExpr(strdup(content));
                            }
                        }
                    }
                    roup_string_list_free(vars);
                } else {
                    // No content
                    new_clause = dir->addOpenMPClause(static_cast<int>(clause_kind), OMPC_IF_MODIFIER_unspecified, (char*)nullptr);
                    if (vars) roup_string_list_free(vars);
                }
                // Skip the variable adding loop for if clauses
                continue;
            }
            // Skip unknown clauses
            else if (clause_kind == OMPC_unknown) {
                continue;
            }
            // Handle simple clauses (just clause kind, no parameters)
            else {
                new_clause = dir->addOpenMPClause(static_cast<int>(clause_kind));
            }

            // Now add variables/expressions if present using addLangExpr
            if (new_clause) {
                OmpStringList* vars = roup_clause_variables(roup_clause);
                if (vars && roup_string_list_len(vars) > 0) {
                    int32_t len = roup_string_list_len(vars);
                    for (int32_t i = 0; i < len; i++) {
                        const char* var = roup_string_list_get(vars, i);
                        if (var) {
                            // ompparser takes ownership of the string via addLangExpr
                            new_clause->addLangExpr(strdup(var));
                        }
                    }
                    roup_string_list_free(vars);
                } else if (vars) {
                    roup_string_list_free(vars);
                }
            }
        }
        roup_clause_iterator_free(iter);
    }

    // Free ROUP directive (we've extracted what we need)
    roup_directive_free(roup_dir);

    return dir;
}

} // extern "C"
